        computed: {            
            paginas_mostradas:function(){
                return PaginasMostradas(this.paginacion);
            },
            fechainicio:function(){                
                if(this.dia_fecha_inicio || this.mes_fecha_inicio || this.anio_fecha_inicio){
                    let dia     =   this.dia_fecha_inicio?this.dia_fecha_inicio:'00';
                    let mes     =   this.mes_fecha_inicio?this.mes_fecha_inicio:'00';
                    let anio    =   this.anio_fecha_inicio?this.anio_fecha_inicio:'0000';

                    return anio + '-' + mes + '-' + dia;
                }else{
                    return '';
                }
            },
            fechafinal:function(){
                if(this.dia_fecha_final || this.mes_fecha_final || this.anio_fecha_final){
                    let dia     =   this.dia_fecha_final?this.dia_fecha_final:'00';
                    let mes     =   this.mes_fecha_final?this.mes_fecha_final:'00';
                    let anio    =   this.anio_fecha_final?this.anio_fecha_final:'0000';

                    return anio + '-' + mes + '-' + dia;
                }else{
                    return '';
                }
            },
            campo_miembro_seleccionado:function(){
