            },
            nombre_periodo:function(){
                let nombre = 'All time';

                if(this.periodo=='cantidad_lecturas_esta_semana'){
                    nombre = 'This week';
                }else if(this.periodo=='cantidad_lecturas_este_mes'){
                    nombre = 'This month';
                }else if(this.periodo=='cantidad_lecturas_este_anio'){
                    nombre = 'This year';
                }else if(this.periodo=='this_quarter'){
                    nombre = 'This quarter';
                }else if(this.periodo=='this_week'){
                    nombre = 'This week';
                }else if(this.periodo=='today'){
                    nombre = 'Today';
                }

                return nombre;
            }
